import React, { useState } from "react";
import { View, Text, TouchableOpacity, StyleSheet } from "react-native";
import type { Event } from "../api";
import { MarkdownView, InlineMarkdown } from "./MarkdownView";

interface Props {
  event: Event;
}

// ─── Helpers ──────────────────────────────────────────────────────────────────

function fmt(iso: string): string {
  const d = new Date(iso);
  return (
    String(d.getHours()).padStart(2, "0") + ":" +
    String(d.getMinutes()).padStart(2, "0") + ":" +
    String(d.getSeconds()).padStart(2, "0")
  );
}

function str(v: unknown): string {
  return typeof v === "string" ? v : "";
}

function data(event: Event): Record<string, unknown> {
  return (event.data ?? {}) as Record<string, unknown>;
}

// Split text into an inline header and a remaining body.
// The header always shows at least HEADER_MIN chars (ignoring sentence
// boundaries that fall before that). The first sentence boundary after
// HEADER_MIN is used as the natural split point, up to HEADER_MAX.
const HEADER_MIN = 75;
const HEADER_MAX = 120;

function splitHeader(text: string): { header: string; body: string } {
  // Strip leading markdown heading markers for a cleaner one-liner
  const trimmed = text.trimStart().replace(/^#{1,3}\s+/, "");

  if (trimmed.length <= HEADER_MIN) {
    return { header: trimmed, body: "" };
  }

  // Find first sentence boundary at or after HEADER_MIN
  let end = trimmed.length;
  for (let i = HEADER_MIN; i < trimmed.length; i++) {
    const c = trimmed[i];
    if (c === "\n") { end = i; break; }
    if (
      (c === "." || c === "!" || c === "?") &&
      (i + 1 >= trimmed.length || trimmed[i + 1] === " " || trimmed[i + 1] === "\n")
    ) {
      end = i + 1;
      break;
    }
  }

  const sentence = trimmed.slice(0, end).trim();
  const after    = trimmed.slice(end).trimStart();

  if (sentence.length <= HEADER_MAX) {
    return { header: sentence, body: after };
  }

  // Sentence is very long — truncate at a word boundary near HEADER_MAX
  const cut = sentence.lastIndexOf(" ", HEADER_MAX);
  const breakAt = cut > HEADER_MAX * 0.6 ? cut : HEADER_MAX;
  const overflow = sentence.slice(breakAt).trimStart();
  return {
    header: sentence.slice(0, breakAt),
    body: (overflow ? "…" + overflow : "") + (after ? "\n\n" + after : ""),
  };
}

// ─── Blocked badge ────────────────────────────────────────────────────────────

function BlockedBadge() {
  return (
    <View style={s.blockedBadge}>
      <Text style={s.blockedText}>BLOCKED</Text>
    </View>
  );
}

// ─── UserPromptSubmit card ────────────────────────────────────────────────────

function UserPromptCard({ event }: { event: Event }) {
  const prompt = str(data(event).prompt);
  const { header, body } = splitHeader(prompt || "(no prompt)");
  return (
    <View style={s.userCard}>
      <View style={[s.cardHeader, !body && s.cardHeaderFlush]}>
        <Text style={s.userLabel}>→ User</Text>
        <InlineMarkdown text={header} style={s.headerSentence} numberOfLines={1} />
        <Text style={s.cardTime}>{fmt(event.timestamp)}</Text>
        {event.blocked && <BlockedBadge />}
      </View>
      {body ? <Text style={s.promptText} selectable>{body}</Text> : null}
    </View>
  );
}

// ─── Stop / Assistant card ────────────────────────────────────────────────────

function AssistantCard({ event }: { event: Event }) {
  const d = data(event);
  const msg = str(d.last_assistant_message);
  const reason = str(d.reason);
  const { header, body } = splitHeader(msg || "(no message)");
  return (
    <View style={s.assistantCard}>
      <View style={[s.cardHeader, !body && s.cardHeaderFlush]}>
        <Text style={s.assistantLabel}>■ Assistant</Text>
        <InlineMarkdown text={header} style={s.headerSentence} numberOfLines={1} />
        {reason ? <Text style={s.reasonBadge}>{reason}</Text> : null}
        <Text style={s.cardTime}>{fmt(event.timestamp)}</Text>
        {event.blocked && <BlockedBadge />}
      </View>
      {body ? <MarkdownView text={body} /> : null}
    </View>
  );
}

// ─── Notification row ─────────────────────────────────────────────────────────

const NOTIF_STYLE: Record<string, { color: string; bg: string; sym: string }> = {
  permission_prompt: { color: "#b45309", bg: "#fffbeb", sym: "?" },
  idle_prompt:       { color: "#6b7280", bg: "#f9fafb", sym: "…" },
};

function NotificationRow({ event }: { event: Event }) {
  const d = data(event);
  const msg = str(d.message);
  const ntype = str(d.notification_type);
  const style = NOTIF_STYLE[ntype] ?? { color: "#6b7280", bg: "#f9fafb", sym: "◆" };
  return (
    <View style={[s.notifRow, { backgroundColor: style.bg }]}>
      <Text style={[s.notifSym, { color: style.color }]}>{style.sym}</Text>
      <Text style={[s.notifMsg, { color: style.color }]}>{msg}</Text>
      <Text style={s.compactTime}>{fmt(event.timestamp)}</Text>
      {event.blocked && <BlockedBadge />}
    </View>
  );
}

// ─── SessionStart / SessionEnd row ────────────────────────────────────────────

function SessionRow({ event }: { event: Event }) {
  const d = data(event);
  const isStart = event.event === "SessionStart";
  const color = "#8b5cf6";
  const sym = isStart ? "◉" : "◎";
  const extra = isStart ? str(d.source) : str(d.reason);
  const cwd = str(d.cwd);
  return (
    <View style={s.sessionRow}>
      <Text style={[s.sessionSym, { color }]}>{sym}</Text>
      <View style={s.sessionBody}>
        <Text style={[s.sessionEvent, { color }]}>{event.event}</Text>
        {extra ? <Text style={s.sessionExtra}>{extra}</Text> : null}
        {cwd ? <Text style={s.sessionCwd} numberOfLines={1}>{cwd}</Text> : null}
      </View>
      <Text style={s.compactTime}>{fmt(event.timestamp)}</Text>
      {event.blocked && <BlockedBadge />}
    </View>
  );
}

// ─── Generic compact row ──────────────────────────────────────────────────────

const EVENT_SYMBOL: Record<string, string> = {
  SubagentStart: "▷",
  SubagentStop: "◁",
  PreCompact: "⌃",
  Setup: "⚙",
  PermissionRequest: "?",
};

const EVENT_COLOR: Record<string, string> = {
  SubagentStart: "#06b6d4",
  SubagentStop: "#06b6d4",
  PreCompact: "#94a3b8",
  Setup: "#94a3b8",
  PermissionRequest: "#f59e0b",
};

function CompactRow({ event }: { event: Event }) {
  const [expanded, setExpanded] = useState(false);
  const sym = EVENT_SYMBOL[event.event] ?? "◆";
  const color = EVENT_COLOR[event.event] ?? "#64748b";
  const d = data(event);
  // Show any interesting text field
  const body = str(d.message) || str(d.reason) || str(d.source);
  const hasBody = body.length > 0;
  return (
    <TouchableOpacity
      onPress={hasBody ? () => setExpanded((v) => !v) : undefined}
      activeOpacity={hasBody ? 0.7 : 1}
      style={s.compactRow}
    >
      <Text style={[s.compactSym, { color }]}>{sym}</Text>
      <Text style={[s.compactEvent, { color }]}>{event.event}</Text>
      <Text style={s.compactTime}>{fmt(event.timestamp)}</Text>
      {event.blocked && <BlockedBadge />}
      {hasBody && <Text style={s.chevron}>{expanded ? "▲" : "▼"}</Text>}
      {expanded && body ? (
        <Text style={s.compactBody}>{body}</Text>
      ) : null}
    </TouchableOpacity>
